mapper.select:
SELECT * FROM grades
WHERE student_id = #{studentId} AND semester = #{semester}
ORDER BY subject ASC

mapper.update:
UPDATE grades
SET subject  = #{subject},
    score    = #{score},
    semester = #{semester}
WHERE id = #{id}

mapper.select:
SELECT ROUND(AVG(score), 1)
FROM grades
WHERE student_id = #{studentId} AND semester = #{semester}
